import React, { useState } from "react";
import "./App.css";
import { array_of_mutants, Original, init } from "./mutants";

/*
                
    Komponens(function/class)  ->  JSX elemek  -> React -> DOM(HTML)
                       A       render                          |
           state változás <-------------------esemény----------      

*/

function Pizza() {
  var [eredmeny, setEredmeny] = useState("-");
  var [killedMutants, setKilledMutants] = useState("-");
  var [testCaseNumber, setNumber] = useState(0);
  var [killed] = useState([]);
  //var [wrongTests, setWrongTests] = useState('')
  var [wrongTests] = useState([]);
  var [printWrongTests, setPrintWrongTests] = useState("");
  var [missing, setMissing] = useState("");
  var [result, setResult] = useState("");
  var [mutant] = useState([]);
  var [wrongSolution, setWrongSolution] = useState(false);
  var [frescaNumber, setFrescaNumber] = useState("0");
  var [polloNumber, setPolloNumber] = useState("0");
  var [beerNumber, setBeerNumber] = useState("0");
  var [cokeNumber, setCokeNumber] = useState("0");
  var [offerBeverage, setOfferBeverage] = useState(false);
  var [beerRemoved, setBeerRemoved] = useState(false);
  var [cokeRemoved, setCokeRemoved] = useState(false);
  var [freeBeer, setFreeBeer] = useState("not yet");
  var [freeCoke, setFreeCoke] = useState("not yet");

  for (var i = 0; i < array_of_mutants.length; i++) {
    if (killed[i] === undefined) {
      killed[i] = false;
    }
  }

  if (wrongTests[0] === undefined) wrongTests[0] = "";

  function nextTest() {
    setBeerNumber(0);
    setCokeNumber(0);
    setFrescaNumber(0);
    setPolloNumber(0);
    setFreeBeer("not yet");
    setFreeCoke("not yet");
    setBeerRemoved(false);
    setCokeRemoved(false);
    setOfferBeverage(false);
    setEredmeny(0);
    init();
  }

  async function downloadTasks() {
    document.getElementById("downloader").click();
  }

  function tryAgain() {
    // window.location.href = '/'
    for (var i = 0; i < array_of_mutants.length; i++) {
      killed[i] = false;
    }
    nextTest();
    setNumber(0);
    setPrintWrongTests("");
    setResult("");
    setMissing("");
  }

  function callFunctions(operation) {
    var fresca = +frescaNumber;
    var pollo = +polloNumber;
    var beer = +beerNumber;
    var coke = +cokeNumber;
    //var mutantVacationDays = 0
    var killedMutants1 = "";

    var result = Original(fresca, pollo, beer, coke, operation, 0);
    var totalPrice = result.totalPrice;
    beerNumber = result.beerNum;
    cokeNumber = result.cokeNum;
    offerBeverage = result.offerBeverage;
    beerRemoved = result.beerRemoved;
    cokeRemoved = result.cokeRemoved;
    freeBeer = result.beerGiven;
    freeCoke = result.cokeGiven;

    setBeerNumber(beerNumber);
    setCokeNumber(cokeNumber);
    setOfferBeverage(offerBeverage);
    setBeerRemoved(beerRemoved);
    setCokeRemoved(cokeRemoved);
    setFreeCoke(freeCoke);
    setFreeBeer(freeBeer);

    setEredmeny(totalPrice); //!!!!!!!!!!!!! go to here!
    var superfluousTest = true;
    var mutantResult = {
      beerNumber: 0,
      cokeNumber: 0,
      totalPrice: 0,
      mutant: "",
    };
    testCaseNumber++;
    for (var i = 0; i < array_of_mutants.length; i++) {
      if (!killed[i]) {
        mutantResult = array_of_mutants[i](
          fresca,
          pollo,
          beer,
          coke,
          operation,
          i + 1
        );
        mutant[i] = mutantResult.mutant;

        if (
          +totalPrice !== +mutantResult.totalPrice ||
          +beerNumber !== +mutantResult.beerNum ||
          +cokeNumber !== +mutantResult.cokeNum ||
          offerBeverage !== mutantResult.offerBeverage ||
          freeBeer !== mutantResult.beerGiven ||
          freeCoke !== mutantResult.cokeGiven ||
          beerRemoved !== mutantResult.beerRemoved ||
          cokeRemoved !== mutantResult.cokeRemoved
        ) {
          var j = i + 1;
          killedMutants1 = killedMutants1 + j + " ";
          killed[i] = true;
          mutant[i] = "";
          superfluousTest = false;
          console.log("killed mutant: ", i + 1);
        }
      }
    }

    setKilledMutants(killedMutants1);
    setNumber(testCaseNumber);
  }

  function printResult() {
    var missingTests = false;
    var missedTestNumber = 0;

    for (var i = 0; i < array_of_mutants.length; i++) {
      if (!killed[i]) {
        missing = "Missing test: " + mutant[i]; //'Some necessary test cases are missing.'
        missingTests = true;
        missedTestNumber++;
        //   console.log('not killed ', i)
      }
    }
    var ratio =
      100 - Math.round((missedTestNumber / array_of_mutants.length) * 100);
    printWrongTests = wrongTests;
    setPrintWrongTests(printWrongTests);

    if (testCaseNumber === 0) {
      result = "Please write your test cases!";
      alert("Please write your test cases!");
      return;
    } else if (
      !missingTests //&&
      //   !wrongSolution &&
      //   testCaseNumber > optimalTestCaseNumber
    ) {
      result = "Congratulation, you are very good at test design!";
      missing = "---";
      setMissing(missing);
      //   } else if (!missingTests && testCaseNumber === optimalTestCaseNumber) {
    } else
      result =
        "You have found " + ratio + "% of the potential bugs. Try again! ";
    setResult(result);
    setMissing(missing);
  }

  return (
    <div className="App">
      <header className="Back-header">
        <p class="Back">
          <a href="https://test-design.org/practical-exercises/">
            Back to Test Design Exercises
          </a>
        </p>
      </header>

      <header className="App-header">
        {console.log("---------------------------")}
        <p class="exercise">
          {" "}
          Read the specification below carefully. Add the test cases one by one.
          A test case ends with 'Next test'. You can continue adding test cases
          after 'Show my result'. <br />
          'Try again' starts a new test design session. &nbsp;&nbsp;You can use
          &nbsp; <a href="https://harmony.test-design.org/">
            Harmony Exercise
          </a>{" "}
          to make action-state test design and execute tests automatedly.
        </p>

        <p class="specification">
          {" "}
          <div style={{ textAlign: "center", fontSize: 20 }}>
            <b> Online pizza ordering </b>
          </div>
          <b>R0</b> In a Pizza Ordering service foods/beverages are offered (the
          prices are in euro): Pizza fresca - 18, Pizza pollo - 15, Coke - 3,
          Beer - 4 <br />
          <b>R1</b> Before any user action is initiated the ordered number of
          items is 0.
          <br />
          <b>R2</b> The user can increase the ordered number of items by
          pressing "+" next to the item. <br />
          <b>R3</b> The user can delete (set to 0) the ordered number of items
          by pressing “X“ next to the item. <br />
          <b>R4</b> If the total price excluding beverages reaches 45 euros for
          the first time, a present beverage is offered to the customer. The
          user can select one free Coke or Beer which is added to the previously
          ordered beverages. ‘Free coke’ or ‘Free beer’ is displayed when a free
          beverage is on the ordered list.
          <br />
          <b>R5</b> The free beverage cannot be changed from coke to beer or
          vice versa. <br />
          <b>R6</b> If the customer deletes food items and goes below 45 euros,
          then the free beverage has been withdrawn until this price remains
          under 45 euros. <br />
          <b>R7</b> The customer can delete the free beverage. When the
          non-beverage price condition holds and she adds the same beverage
          again, it remains free. <br />
          <b>R8</b> The customer can clear all the items. Adding enough foods
          again she can select any free beverage. &nbsp;&nbsp;{" "}
        </p>

        <p class="testcases">
          <div>
            {missing.length > 0 ? (
              <span data-harmony-id="Missing test">
                {" "}
                {missing} <br />
              </span>
            ) : (
              <span data-harmony-id="Wrong test">
                {" "}
                {wrongTests[0]} <br />
              </span>
            )}
          </div>
          <span data-harmony-id="result">{result}</span> <br />
          <br />
          <span style={{ textAlign: "left" }}>Pizza fresca: </span>
          <span
            data-harmony-id="Fresca number"
            style={{ color: "mediumaquamarine" }}
          >
            {frescaNumber}
          </span>{" "}
          <button
            class="button"
            data-harmony-id="fresca + button"
            onClick={() => {
              frescaNumber++;
              setFrescaNumber(frescaNumber);
              callFunctions("add fresca");
            }}
          >
            <b>+</b>
          </button>
          <button
            class="button"
            data-harmony-id="fresca X button"
            onClick={() => {
              if (frescaNumber > 0) {
                frescaNumber = 0;
                setFrescaNumber(frescaNumber);
                callFunctions("remove fresca");
              }
            }}
          >
            <b>X</b>
          </button>
          &nbsp;&nbsp;&nbsp;&nbsp;Pizza pollo:{" "}
          <span
            data-harmony-id="pollo number"
            style={{ color: "mediumaquamarine" }}
          >
            {polloNumber}
          </span>{" "}
          <button
            class="button"
            data-harmony-id="pollo + button"
            onClick={() => {
              polloNumber++;
              setPolloNumber(polloNumber);
              callFunctions("add pollo");
            }}
          >
            <b>+</b>
          </button>
          <button
            class="button"
            data-harmony-id="pollo X button"
            onClick={() => {
              if (polloNumber > 0) {
                polloNumber = 0;
                setPolloNumber(polloNumber);
                callFunctions("remove pollo");
              }
            }}
          >
            <b>X</b>
          </button>
          &nbsp;&nbsp;&nbsp;&nbsp;Beer:{" "}
          <span
            data-harmony-id="Beer number"
            style={{ color: "mediumaquamarine" }}
          >
            {beerNumber}
          </span>{" "}
          <button
            class="button"
            data-harmony-id="Beer + button"
            id="Beer + button"
            onClick={() => {
              beerNumber++;
              setBeerNumber(beerNumber);
              callFunctions("add beer");
            }}
          >
            <b>+</b>
          </button>
          <button
            class="button"
            data-harmony-id="Beer X button"
            onClick={() => {
              if (beerNumber > 0) {
                beerNumber = 0;
                setBeerNumber(beerNumber);
                callFunctions("remove beer");
              }
            }}
          >
            <b>X</b>
          </button>
          &nbsp;&nbsp;&nbsp;&nbsp;Coke:{" "}
          <span
            data-harmony-id="Coke number"
            style={{ color: "mediumaquamarine" }}
          >
            {cokeNumber}
          </span>{" "}
          <button
            class="button"
            data-harmony-id="Coke + button"
            id="Coke + button"
            onClick={() => {
              cokeNumber++;
              setCokeNumber(cokeNumber);
              callFunctions("add coke");
            }}
          >
            <b>+</b>
          </button>
          <button
            class="button"
            data-harmony-id="Coke X button"
            onClick={() => {
              if (cokeNumber > 0) {
                cokeNumber = 0;
                setCokeNumber(cokeNumber);
                callFunctions("remove coke");
              }
            }}
          >
            <b>X</b>
          </button>
          &nbsp;&nbsp;&nbsp;&nbsp; Total price:{" "}
          <span data-harmony-id="Total price">{eredmeny}</span>
          &nbsp;&nbsp;&nbsp;
          {offerBeverage && (
            <button
              class="button"
              data-harmony-id="free beer"
              onClick={() => {
                callFunctions("free beer selected");
              }}
            >
              Add free beer
            </button>
          )}
          &nbsp;&nbsp;&nbsp;
          {offerBeverage && (
            <button
              class="button"
              data-harmony-id="free coke"
              onClick={() => {
                callFunctions("free coke selected");
              }}
            >
              Add free coke
            </button>
          )}
          {!offerBeverage &&
            !(freeBeer === "yes" && !beerRemoved) &&
            !(freeCoke === "yes" && !cokeRemoved) && (
              <span>
                {" "}
                &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;{" "}
              </span>
            )}
          {freeBeer === "yes" && !beerRemoved && (
            <span style={{ color: "yellow" }}>
              Free beer added
              &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
            </span>
          )}
          {freeCoke === "yes" && !cokeRemoved && (
            <span style={{ color: "yellow" }}>
              Free coke added
              &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
            </span>
          )}
          &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
          <button
            class="clear"
            data-harmony-id="clear all"
            onClick={() => {
              frescaNumber = 0;
              setFrescaNumber(frescaNumber);
              polloNumber = 0;
              setPolloNumber(0);
              callFunctions("clear all");
            }}
          >
            Clear all
          </button>
          <br /> <br />
          <button class="button" data-harmony-id="Next test" onClick={nextTest}>
            {" "}
            Next test{" "}
          </button>{" "}
          &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
          <button class="button" data-harmony-id="Stop" onClick={printResult}>
            {" "}
            Show my result{" "}
          </button>{" "}
          &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
          <button class="button" data-harmony-id="Try again" onClick={tryAgain}>
            {" "}
            Try again{" "}
          </button>{" "}
          &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
          &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
          &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
          &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
          {/*
          <button
            class="download"
            data-harmony-id="Download"
            onClick={downloadTasks}
          >
            {" "}
            Download templates{" "}
          </button>{" "}
          <a
            id="downloader"
            href="../templates/pizza_templates.zip"
            download
            hidden
          ></a>
          */}
          <br />
        </p>
      </header>
    </div>
  );
}

export default Pizza;
